#include <vector>
#include <string>
#include <unordered_set>

using namespace std;

vector<string> solve(string s) {
    vector<string> segments;
    unordered_set<string> seen;
    int start = 0;
    while (start < s.length()) {
        string current;
        while (true) {
            current += s[start];
            if (seen.find(current) == seen.end()) {
                seen.insert(current);
                segments.push_back(current);
                break;
            } else {
                start++;
            }
        }
        start++;
    }
    return segments;
}
